INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-e0adf6cd-moex-00089', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「四月五，烏沉香插遍山崗古墓。彎形鐮刀只斬五節芒、爬墓藤，不斬家國血脈。數百年來 滄桑渡海，何曾畏懼狂浪噬舟？縱使船破人浮，猶掌握一線香袋不容盡濕，遂扶老攜幼，家 祠南來。」 根據上文，下列選項正確的是：', '["描寫清明節的掃墓活動", "慎終追遠是不可或忘的文化傳統", "「掌握一線香袋」意指配戴廟宇祈求的平安符", "「數百年來滄桑渡海」是形容祖先為了謀生，拋家棄子獨自來到異鄉 祖先為了謀生離鄉背井，無論是替人整理墓地，或是冒險捕魚的工作都願意做"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00090', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '古之君子有所為、有所不為，即使處於逆境，仍能堅守節操，不同流合汙。 根據上文，下列選項何者符合文意？', '["時窮節乃見，一一垂丹青", "舉世皆濁我獨清，眾人皆醉我獨醒", "使其中坦然不以物傷性，將何適而非快", "吾不能變心而從俗兮，固將愁苦而終窮 君子之所取者遠，則必有所待；所就者大，則必有所忍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00091', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「番薯是原產於拉丁美洲的作物。日文裡的番薯稱為『薩摩芋』，意即來自薩摩地區，這個 稱呼主要在日本的本州以北使用，在北九州則有『琉球芋』之稱，可是南九州、沖繩又以『唐 芋』稱呼。同樣在中國，浙東地區士大夫編纂地方誌時，就舉出『番芋』是舟山群島的特產 之一，並在說明『味甚甘美』的同時，也記載了『種來自日本』，而番薯的『番』是指日本。」 根據上文，下列選項何者符合文意？', '["番薯雖原產於拉丁美洲，但在亞洲成為重要的主食", "日本的本州與南北九州，對番薯有三種不同的稱呼", "沖繩對番薯的說法差異，主要是受到經濟文化影響", "人們對番薯的各種稱呼，反映對其來源的不同看法 番薯應是舟山群島特產，但中國士人以為來自日本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00092', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '古人曾言「所種者穀，雖瘠土墮農，不生稗也；所種者稗，雖美田疾耕，不生穀也。」 根據上文，下列選項何者符合文意？', '["水到渠成，不須預慮", "江山易改，本性難移", "種瓜得瓜，種豆得豆", "貧不學儉，富不學奢 蓬生麻中，不扶自直"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00093', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '落日千林紫，漁舟聚淺灘。飛蓬雲外沒，野鳥望中還。寺小藏深樹，潮寬點亂山。一樽頻對 此，無意羨人間。（宋懋澄〈晚色〉） 根據上詩，下列敘述何者正確？', '["刻畫景物，藉景抒情", "蘊含瀟灑的出世之想", "充滿山水意趣，富有情韻", "描寫晚景，宛如一幅山水畫卷 近似「夕陽無限好，只是近黃昏」之意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00094', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「畫家在素描時，勒定了所畫對象大約的輪廓後，只以炭筆磨擦出光影的陰暗與明亮，而不 做細部的描繪，保持一點朦朧感，以免整個畫面過於呆板。這個階段，就像詩一樣，在光與 暗、有與無之間，帶著一點迷濛，一點神祕，一點耐人追索的況味。然而這並非脫離現實， 仔細想想，我們在人生裡，大多數的情感都是這樣迷濛的吧！誰能肯定自己的內心無論是哪 一刻都清晰無比的呢？」 根據上文，下列選項正確的是：', '["擅長讀詩的人擁有最單純的心思，對世事經常感到懵懵懂懂", "詩在指涉、內涵上的模糊性，常能帶給讀者解釋探索的趣味", "詩與素描一樣，都不可進行細部描繪，才能提升整體的美感", "思緒清明的人難以享受讀詩之樂，因複雜處能輕易迎刃而解 生命中多數情感一如詩般迷濛，從詩中可以體會人生與現實"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00095', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-34c7f7f6', 'sub-elementary-e0adf6cd-02', NULL, 'single_choice', '「ChatGPT或Bing Chat多是提供定義式的短語，回覆的內容主要是『已知』的有限資訊， 難以『多義性』的語言表現感知複雜的人類思維。這是因為 AI 的訓練出自設計者目前的偏 好或定見，如果想讓AI更貼近人類需求，就必須仰賴人類持續更新且多樣化的經驗。」 根據上文，下列選項正確的是：', '["目前AI程式設計者偏好取樣多元的生活經驗", "AI現在仍未取代人類思想情感的複雜性表現", "AI設計者皆偏愛不受感知影響的科學性語言", "目前AI是以短語提供快速單一的資訊為目的 不斷轉型的語言文化和科技趨勢無直接關係"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:36+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00096', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '乙生多次以言語及肢體欺負同學，因此甲導師決定將他記大過並公告於公布欄。甲導師採取了下列何種懲 罰策略？', '["報應性的懲罰", "懲戒性的懲罰", "感化性的懲罰", "恕道性的懲罰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00097', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '丙老師認為教育的目的不在於傳遞知識而已，更重要的是美好德行的養成。他的想法較接近下列何位學者 的觀點？', '["柏拉圖（Plato）", "皮亞傑（J.Piaget）", "郭爾堡（L.Kohlberg）", "亞里斯多德（Aristotle）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00098', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-f2876bfc', 'sub-elementary-e0adf6cd-03', NULL, 'single_choice', '下列何者是一種教育的「口號」？', '["教育是多樣態的歷程", "教育即雕刻", "教育即生長", "教育要鬆綁"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "bcc25c65bb7f", "answer_pdf_sha1": "73f1ecdcd54a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
